function getRandomFloat(min, max) {
  return parseFloat((Math.random() * (max - min) + min).toFixed(2));
}

msg.deviceType = flow.get("deviceTypeId");
msg.deviceId = msg.payload;
msg.eventOrCommandType = flow.get("eventId");

msg.payload = {
    "temperature": getRandomFloat(24, 26),
    "humidity": getRandomFloat(1, 15)
};

return msg;

// This function expects a target number of devices to simulate as an input, 
// and generates a CSV output consisting of the device IDs to be used for
// the simulation

// ex. prefix == 20West, suffix == 1, deviceId == 20West001
function formatDeviceId(prefix, suffix) {
    return prefix + ("00" + suffix).slice(-3);
}

var numOfDevices = flow.get("numOfDevices");
var deviceIdPrefix = flow.get("deviceIdPrefix");

var deviceIdCsv = "";
for (deviceIdSuffix = 1; deviceIdSuffix < numOfDevices + 1; deviceIdSuffix++) {
    deviceIdCsv += formatDeviceId(deviceIdPrefix, deviceIdSuffix) + ",";
}
// Chop off trailing comma
deviceIdCsv = deviceIdCsv.slice(0, -1);

msg.payload = deviceIdCsv;
return msg;

// ex. prefix == 20West, suffix == 1, deviceId == 20West001
function formatDeviceId(prefix, suffix) {
    return prefix + ("00" + suffix).slice(-3);
}

var numOfDevices = flow.get("numOfDevices");
var deviceTypeId = flow.get("deviceTypeId");
var deviceIdPrefix = flow.get("deviceIdPrefix");

var bulkDeviceCreateReq = []
for (deviceIdSuffix = 1; deviceIdSuffix < numOfDevices + 1; deviceIdSuffix++) {
    deviceId = formatDeviceId(deviceIdPrefix, deviceIdSuffix);
    bulkDeviceCreateReq.push({
        typeId: deviceTypeId,
        deviceId: deviceId,
        authToken: deviceId
    });
}

msg.payload = bulkDeviceCreateReq;
return msg;

rgb_color = ''

if(msg.payload.humidity <= 33){
    // Green
    rgb_color = "0, 255, 0"; 
}
else if(msg.payload.humidity <= 66){
    // Yellow
    rgb_color = "255, 255, 0"; 
}
else {
    // Red
    rgb_color = "255, 0, 0"
}

msg.payload = {color: rgb_color, humidity: Math.floor(msg.payload.humidity)}

return msg;

//CSS ID start with a letter
