device = msg.deviceId;

floor = parseInt(device.slice(0, 2));

east_west = device.slice(2, 6);

tower = "";
if(east_west == "East")
{
    tower = "T1";
}
else if(east_west == "West")
{
    tower = "T2";
}

north_south = parseInt(device.slice(12));

side = "";
if(floor == 20)
{
    if(north_south > 2)
    {
        side = "North";
    }
    else
    {
        side = "South";
    }
}
else if(floor == 21)
{
    if(north_south > 2)
    {
        side = "South";
    }
    else
    {
        side = "North";
    }
}

location = "Tower " + String(tower); 
location += ", Floor " + String(floor);
location += ", " + side;

msg.payload = {humidity: msg.payload.humidity, location:location}
